  ('medical-tech-moex-05246', 'medical-tech', 'medical-tech-moex-110-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '焦磷酸定序（pyrosequencing）是一種廣泛應用於腫瘤突變檢測的技術，其優點為引子延伸反應和定序同時進 行，可免去電泳的步驟。下圖為一焦磷酸定序的結果，關於標的片段的DNA序列，下列何者正確？', '["AGTGCTGTG", "AGTCAGTCAGTCAGTCAG", "AGGGGTGGCTTTGGGGTTG", "GGGGTTGGGT"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:23+00:00", "source_pdf_sha1": "50b45af8129b", "answer_pdf_sha1": "f496f9a57809", "source_family": "moex-gov-tw", "moex": {"exam_code": "110020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "110", "exam_name": "110年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 72, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
